const output = [];

for (const item of $input.all()) {
  const rawOutput = item.json.output;

  // Extract the content inside ```json ... ```
  const jsonMatch = rawOutput.match(/```json\s*([\s\S]*?)```/);

  if (!jsonMatch || !jsonMatch[1]) {
    output.push({ json: { error: "No valid JSON block found" } });
    continue;
  }

  let cleaned = jsonMatch[1].trim();

  // Fix: Replace `content`: `...` with proper JSON string
  // Match: "content": `...`
  cleaned = cleaned.replace(/"content":\s*`([\s\S]*?)`(?=,|\n|\})/g, (match, content) => {
    const escaped = content
      .replace(/\\/g, "\\\\")          // escape backslashes
      .replace(/"/g, '\\"')            // escape double quotes
      .replace(/\r?\n/g, "\\n");       // escape newlines
    return `"content": "${escaped}"`;
  });

  try {
    const parsed = JSON.parse(cleaned);

    // Push all parsed objects (if array) or single object
    if (Array.isArray(parsed)) {
      for (const entry of parsed) {
        output.push({ json: entry });
      }
    } else {
      output.push({ json: parsed });
    }

  } catch (err) {
    output.push({ json: { error: "Failed to parse JSON", message: err.message } });
  }
}

return output;

