const output = [];

for (const item of $input.all()) {
  const rawOutput = item.json.output;

  // Extract JSON block between ```json ... ```
  const jsonMatch = rawOutput.match(/```json\s*([\s\S]*?)```/);

  if (jsonMatch && jsonMatch[1]) {
    try {
      const parsed = JSON.parse(jsonMatch[1].trim());

      // Transform into desired structure
      const transformed = {
        data: {
        id: parsed.post_id,
        version: 0,
        categorySet: [
          { id: parsed.category.id,
            name:parsed.category.name
          }
        ]
      }}

      output.push({ json: {req:transformed} });
    } catch (err) {
      output.push({ json: { error: "Invalid JSON", message: err.message } });
    }
  } else {
    output.push({ json: { error: "No JSON block found" } });
  }
}

return output;

